#include<bits/stdc++.h>
using namespace std;
long long jc[200010],ny[200010];
int n,m,p;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%p;
        }
        x=x*x%p;
        y/=2;
    }
    return ans;
}
long long C(long long n,long long m)
{
    if(n<m)
    {
        return 0;
    }
    return jc[n]*ny[m]%p*ny[n-m]%p;
}
long long lucas(long long n,long long m)
{
    if(n<m)
    {
        return 0;
    }
    if(m==0)
    {
        return 1;
    }
    return lucas(n/p,m/p)*C(n%p,m%p)%p;
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        jc[0]=ny[0]=1;
        scanf("%d%d%d",&n,&m,&p);
        for(int i=1;i<p;i++)
        {
            jc[i]=jc[i-1]*i%p;
        }
        ny[p-1]=fastpow(jc[p-1],p-2);
        for(int i=p-2;i>=1;i--)
        {
            ny[i]=ny[i+1]*(i+1)%p;
        }
        printf("%lld\n",lucas(n+m,n));
    }
    return 0;
}
